import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface DailyRange {
  day: string;
  humidity: number;
  dewPoint: number;
}

interface WeatherData {
  location: string;
  current: {
    humidity: number;
    dewPoint: number;
    comfortLevel: string;
  };
  dailyRange: DailyRange[];
}

export default function Widget() {
  const weatherData = response.data as WeatherData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {weatherData.location}
            </Typography>
            <Typography variant="h6" fontWeight={500} sx={{ color: '#3F51B5' }}>
              Current Comfort Level: {weatherData.current.comfortLevel}
            </Typography>
            <Stack direction="row" spacing={1}>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Humidity
                </Typography>
                <Typography variant="body2" fontWeight={500} color="primary">
                  {weatherData.current.humidity}%
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Dew Point
                </Typography>
                <Typography variant="body2" fontWeight={500} color="primary">
                  {weatherData.current.dewPoint}°F
                </Typography>
              </Box>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: weatherData.dailyRange.map((d) => d.humidity),
                  color: '#FF5722',
                  label: 'Humidity',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weatherData.dailyRange.map((d) => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'humidity' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="humidity"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
